+    #[test]
+    fn test_cli_parse_init_auto() {
+        let cli = Cli::parse_from(["dcg", "init", "--auto"]);
+        if let Some(Command::Init { auto, dry_run, .. }) = cli.command {
+            assert!(auto);
+            assert!(!dry_run);
+        } else {
+            unreachable!("Expected Init command");
+        }
+    }
