+        let cli = Cli::parse_from(["dcg", "init", "--dry-run"]);
+        if let Some(Command::Init { dry_run, auto, .. }) = cli.command {
+            assert!(dry_run);
+            assert!(!auto);
+        } else {
+            unreachable!("Expected Init command");
